1	'use strict';
2	// llm/gate.js - THE post-hoc structural gate every LLM response passes before any consumer sees it
3	// (Constitution Rule 11 + Rule 12 gates 1-2, GAPS.md llm-unverified). Deterministic, no network,
4	// fail-closed. A rejected response NEVER reaches a consumer: the gate returns ABSTAIN semantics
5	// (ok:false, value:null), never a repaired or partial answer.
6	//
7	//   validateResponse(response, { schema, allowedSourceIds, sources, minQuoteLen }) ->
8	//     { ok:true,  value, violations:[] }                     (accepted)
9	//     { ok:false, value:null, abstain:true, violations[] }   (refused; the failure mode is silence)
10	//
11	// The three deterministic checks (research grounding: docs/discovery/digest-research-llm-agents.md
12	// Part A, patterns 1, 2 and 6/7 - schema guarantees SHAPE, not truth, so a separate semantic gate
13	// must follow):
14	//   0. PARSE          unparseable JSON = reject. A model reply that is not valid JSON is refused, it
15	//                     is never coerced (caution.md C-137: the parse-fragile prompt-only-JSON lane).
16	//   1. SCHEMA         a tiny built-in JSON-Schema subset validates required fields, types, enums and
17	//                     bounds. No new dependency (Constitution: zero runtime deps); mirrors the pure
18	//                     path-list validator style of payload/contract/index.js.
19	//   2. RETRIEVAL-GATE every cited source_id must be a member of allowedSourceIds (Rule 12 gate 1). An
20	//                     out-of-set citation is a HARD reject - the escape probability of a fabricated
21	//                     citation is zero, not small (13-21% of legal citations hallucinate, arXiv 2606.00898).
22	//   3. QUOTE RE-MATCH every quote must survive a normalised exact-substring match against the source
23	//                     text it cites (Rule 12 gate 2). A paraphrased or fabricated quote drifts and is
24	//                     rejected (models paraphrase inside quotation marks, Stanford HAI).
25	//
26	// This gate checks the citations a response ACTUALLY makes. The stronger policy "a violation MUST
27	// cite an artifact / a NO_BREACH MUST carry a disproof quote" (caution.md C-080/C-092) is the
28	// ADJUDICATOR's contract (breach/adjudicator, Wave 2) and composes ON TOP of this structural gate.
29	
30	const DEFAULT_MIN_QUOTE_LEN = 8;   // caution.md C-089: sub-25-char nav fragments are not evidence; 8 is the H.anchored floor ported from the proven gate, callers (the adjudicator) raise it.
31	const MAX_WALK_DEPTH = 12;         // adversarial deeply-nested response guard (caution.md C-165 red-team inputs); beyond this we stop walking rather than blow the stack.
32	const SOURCE_ID_KEY = /^source_ids?$/i;
33	const QUOTE_FIELDS = ['quote', 'verbatim_quote'];
34	
35	// ---------------------------------------------------------------------------------------------------
36	// Small pure helpers
37	// ---------------------------------------------------------------------------------------------------
38	
39	// normalise(s): the canonical form for the verbatim-quote substring match. Lowercase, collapse all
40	// whitespace runs to a single space, fold curly quotes to straight (both sides of the compare get the
41	// same folding, so the comparison stays exact, never fuzzy). caution.md C-035: detection surface and
42	// evidence surface must be the SAME normalised corpus.
43	function normalise(s) {
44	  return String(s == null ? '' : s)
45	    .replace(/[‘’]/g, "'")
46	    .replace(/[“”]/g, '"')
47	    .replace(/\s+/g, ' ')
48	    .trim()
49	    .toLowerCase();
50	}
51	
52	// toSet(arr): a Set of trimmed string ids. A non-array yields the EMPTY set, so a caller that forgot
53	// to supply the retrieval set can cite NOTHING (fail-closed): every id is then out-of-set.
54	function toSet(arr) {
55	  const s = new Set();
56	  for (const x of Array.isArray(arr) ? arr : []) s.add(String(x).trim());
57	  return s;
58	}
59	
60	function typeOf(v) {
61	  if (v === null) return 'null';
62	  if (Array.isArray(v)) return 'array';
63	  return typeof v;
64	}
65	
66	function sv(path, message) {
67	  return { code: 'schema', path, message: 'schema ' + path + ': ' + message };
68	}
69	
70	// safeRegex(pattern): compile a schema `pattern`. An invalid pattern cannot validate anything, so we
71	// return a never-match regex - the field is then flagged as not matching, keeping the gate fail-closed.
72	function safeRegex(pattern) {
73	  try {
74	    return new RegExp(pattern);
75	  } catch (_e) {
76	    // FAIL-OPEN: an invalid schema pattern is a config error; the never-match keeps the field flagged
77	    // and the SYSTEM fail-closed (the value is reported as a schema violation, never silently passed).
78	    return /$.^/;
79	  }
80	}
81	
82	// ---------------------------------------------------------------------------------------------------
83	// Step 0: parse
84	// ---------------------------------------------------------------------------------------------------
85	
86	// pickText(response): the text payload to parse. Accepts a raw string, a router response object with a
87	// string `.text`, or null when neither is present (the caller may then treat an object as pre-parsed).
88	function pickText(response) {
89	  if (typeof response === 'string') return response;
90	  if (response && typeof response.text === 'string') return response.text;
91	  return null;
92	}
93	
94	// extractJson(text): the substring from the first JSON opener to the last closer, or null. A model that
95	// wraps JSON in prose or ```fences still yields its object; genuinely non-JSON text yields null.
96	function extractJson(text) {
97	  const s = String(text);
98	  const starts = [s.indexOf('{'), s.indexOf('[')].filter((i) => i !== -1);
99	  if (!starts.length) return null;
100	  const start = Math.min(...starts);
101	  const end = Math.max(s.lastIndexOf('}'), s.lastIndexOf(']'));
102	  if (end <= start) return null;
103	  return s.slice(start, end + 1);
104	}
105	
106	// parseResponse(response): { ok:true, value } or { ok:false, violation }. A failed router response
107	// (ok:false) and an unparseable body both route to a typed reject, so the gate can abstain cleanly.
108	function parseResponse(response) {
109	  if (response == null) return { ok: false, violation: { code: 'empty_response', message: 'no response supplied' } };
110	  if (typeof response === 'object' && response.ok === false) {
111	    return { ok: false, violation: { code: 'provider_unavailable', message: 'router returned ok:false (' + String(response.reason || response.error || 'unknown') + ')' } };
112	  }
113	  const text = pickText(response);
114	  if (text === null) {
115	    if (typeof response === 'object') return { ok: true, value: response };
116	    return { ok: false, violation: { code: 'empty_response', message: 'response carried no text' } };
117	  }
118	  const slice = extractJson(text);
119	  if (slice === null) return { ok: false, violation: { code: 'unparseable_json', message: 'no JSON object or array found in the response text' } };
120	  try {
121	    return { ok: true, value: JSON.parse(slice) };
122	  } catch (_e) {
123	    // FAIL-OPEN: a JSON.parse throw is caught HERE and converted to a typed reject; validateResponse
124	    // then returns abstain (ok:false), so the SYSTEM fails closed - a malformed reply never ships.
125	    return { ok: false, violation: { code: 'unparseable_json', message: 'the response text is not valid JSON' } };
126	  }
127	}
128	
129	// ---------------------------------------------------------------------------------------------------
130	// Step 1: schema (a tiny JSON-Schema subset, zero dependencies)
131	// ---------------------------------------------------------------------------------------------------
132	
133	function oneTypeMatches(value, t) {
134	  if (t === 'integer') return typeof value === 'number' && Number.isInteger(value);
135	  if (t === 'number') return typeof value === 'number' && Number.isFinite(value);
136	  if (t === 'object') return typeOf(value) === 'object';
137	  if (t === 'array') return Array.isArray(value);
138	  if (t === 'null') return value === null;
139	  return typeof value === t;
140	}
141	
142	function typeMatches(value, t) {
143	  const types = Array.isArray(t) ? t : [t];
144	  return types.some((one) => oneTypeMatches(value, one));
145	}
146	
147	function checkStringConstraints(value, schema, path) {
148	  const out = [];
149	  if (Number.isFinite(schema.minLength) && value.length < schema.minLength) out.push(sv(path, 'string shorter than minLength ' + schema.minLength));
150	  if (Number.isFinite(schema.maxLength) && value.length > schema.maxLength) out.push(sv(path, 'string longer than maxLength ' + schema.maxLength));
151	  if (schema.pattern && !safeRegex(schema.pattern).test(value)) out.push(sv(path, 'string does not match pattern ' + JSON.stringify(schema.pattern)));
152	  return out;
153	}
154	
155	function checkNumberConstraints(value, schema, path) {
156	  const out = [];
157	  if (Number.isFinite(schema.minimum) && value < schema.minimum) out.push(sv(path, 'number below minimum ' + schema.minimum));
158	  if (Number.isFinite(schema.maximum) && value > schema.maximum) out.push(sv(path, 'number above maximum ' + schema.maximum));
159	  return out;
160	}
161	
162	function checkScalarConstraints(value, schema, path) {
163	  const out = [];
164	  if (schema.enum && !schema.enum.some((e) => e === value)) out.push(sv(path, 'value ' + JSON.stringify(value) + ' not in enum ' + JSON.stringify(schema.enum)));
165	  if ('const' in schema && schema.const !== value) out.push(sv(path, 'value must equal ' + JSON.stringify(schema.const)));
166	  if (typeof value === 'string') out.push(...checkStringConstraints(value, schema, path));
167	  if (typeof value === 'number') out.push(...checkNumberConstraints(value, schema, path));
168	  return out;
169	}
170	
171	function checkObject(value, schema, path) {
172	  const out = [];
173	  for (const key of schema.required || []) {
174	    if (!(key in value) || value[key] === undefined) out.push(sv(path + '.' + key, 'required property missing'));
175	  }
176	  const props = schema.properties || {};
177	  for (const [key, sub] of Object.entries(props)) {
178	    if (key in value) out.push(...validateSchema(value[key], sub, path + '.' + key));
179	  }
180	  if (schema.additionalProperties === false) {
181	    for (const key of Object.keys(value)) {
182	      if (!(key in props)) out.push(sv(path + '.' + key, 'additional property not permitted'));
183	    }
184	  }
185	  return out;
186	}
187	
188	function checkArray(value, schema, path) {
189	  const out = [];
190	  if (Number.isFinite(schema.minItems) && value.length < schema.minItems) out.push(sv(path, 'array shorter than minItems ' + schema.minItems));
191	  if (Number.isFinite(schema.maxItems) && value.length > schema.maxItems) out.push(sv(path, 'array longer than maxItems ' + schema.maxItems));
192	  if (schema.items) value.forEach((el, i) => out.push(...validateSchema(el, schema.items, path + '[' + i + ']')));
193	  return out;
194	}
195	
196	// validateSchema(value, schema, path): the recursive shape check. A type mismatch short-circuits (deeper
197	// checks on the wrong shape are noise); otherwise scalar bounds, object and array rules all apply.
198	function validateSchema(value, schema, path) {
199	  if (!schema || typeof schema !== 'object') return [];
200	  if (schema.nullable && value === null) return [];
201	  if (schema.type && !typeMatches(value, schema.type)) {
202	    return [sv(path, 'expected ' + JSON.stringify(schema.type) + ', got ' + typeOf(value))];
203	  }
204	  const out = checkScalarConstraints(value, schema, path);
205	  if (typeOf(value) === 'object') out.push(...checkObject(value, schema, path));
206	  else if (Array.isArray(value)) out.push(...checkArray(value, schema, path));
207	  return out;
208	}
209	
210	// ---------------------------------------------------------------------------------------------------
211	// Step 2/3: collect citations, then retrieval-gate and quote-match them
212	// ---------------------------------------------------------------------------------------------------
213	
214	function pushSourceIds(v, path, acc) {
215	  if (typeof v === 'string') { acc.sourceIds.push({ id: v, path }); return; }
216	  if (Array.isArray(v)) {
217	    v.forEach((el, i) => { if (typeof el === 'string') acc.sourceIds.push({ id: el, path: path + '[' + i + ']' }); });
218	  }
219	}
220	
221	function firstQuoteField(node) {
222	  for (const key of QUOTE_FIELDS) {
223	    if (typeof node[key] === 'string') return node[key];
224	  }
225	  return null;
226	}
227	
228	// gatherNodeCitations(node, path, acc): pull the source_id citations and any quote+source_id pair out
229	// of ONE object node. A quote is bound to the source_id declared on the SAME object (Rule 12 gate 2:
230	// a quote must cite the document it came from).
231	function gatherNodeCitations(node, path, acc) {
232	  for (const [k, v] of Object.entries(node)) {
233	    if (SOURCE_ID_KEY.test(k)) pushSourceIds(v, path ? path + '.' + k : k, acc);
234	  }
235	  const quote = firstQuoteField(node);
236	  const sid = typeof node.source_id === 'string' ? node.source_id : null;
237	  if (quote != null && sid != null) acc.quotes.push({ quote, sourceId: sid, path });
238	}
239	
240	// walkCitations(node, path, depth, acc): a single depth-bounded walk of the parsed value, gathering
241	// every cited source_id and every quote/source_id pair for the flat checks that follow.
242	function walkCitations(node, path, depth, acc) {
243	  if (depth > MAX_WALK_DEPTH || node == null || typeof node !== 'object') return;
244	  if (Array.isArray(node)) {
245	    node.forEach((el, i) => walkCitations(el, path + '[' + i + ']', depth + 1, acc));
246	    return;
247	  }
248	  gatherNodeCitations(node, path, acc);
249	  for (const [k, v] of Object.entries(node)) walkCitations(v, path ? path + '.' + k : k, depth + 1, acc);
250	}
251	
252	function collectCitations(value) {
253	  const acc = { sourceIds: [], quotes: [] };
254	  walkCitations(value, '$', 0, acc);
255	  return acc;
256	}
257	
258	// checkSourceIds(sourceIds, allowedSet): Rule 12 gate 1. Every cited id must be in the retrieval set.
259	function checkSourceIds(sourceIds, allowedSet) {
260	  const out = [];
261	  for (const { id, path } of sourceIds) {
262	    const norm = String(id).trim();
263	    if (!allowedSet.has(norm)) {
264	      out.push({ code: 'out_of_set_source_id', path, id: norm, message: 'cited source_id "' + norm + '" is not in the retrieval set (Rule 12 gate 1)' });
265	    }
266	  }
267	  return out;
268	}
269	
270	// checkOneQuote(q, sources, minQuoteLen, allowedSet): Rule 12 gate 2 for one quote/source_id pair. The
271	// order of checks is deliberate: too-short, then in-set, then source-present, then verbatim substring.
272	function checkOneQuote(q, sources, minQuoteLen, allowedSet) {
273	  const sid = String(q.sourceId).trim();
274	  const text = String(q.quote || '');
275	  if (text.trim().length < minQuoteLen) return [{ code: 'quote_too_short', path: q.path, sourceId: sid, message: 'quote is shorter than the ' + minQuoteLen + '-char floor (caution.md C-089)' }];
276	  if (!allowedSet.has(sid)) return [{ code: 'out_of_set_source_id', path: q.path, id: sid, message: 'quote cites source_id "' + sid + '" not in the retrieval set (Rule 12 gate 1)' }];
277	  const src = sources ? sources[sid] : null;
278	  if (src == null) return [{ code: 'quote_source_missing', path: q.path, sourceId: sid, message: 'no source text supplied for "' + sid + '"; the quote cannot be verified, so the claim is refused' }];
279	  if (!normalise(src).includes(normalise(text))) return [{ code: 'quote_drift', path: q.path, sourceId: sid, message: 'quote is not a verbatim substring of source "' + sid + '" (Rule 12 gate 2)' }];
280	  return [];
281	}
282	
283	function checkQuotes(quotes, sources, minQuoteLen, allowedSet) {
284	  const out = [];
285	  for (const q of quotes) out.push(...checkOneQuote(q, sources, minQuoteLen, allowedSet));
286	  return out;
287	}
288	
289	// ---------------------------------------------------------------------------------------------------
290	// The gate
291	// ---------------------------------------------------------------------------------------------------
292	
293	function abstain(violations) {
294	  return { ok: false, value: null, abstain: true, violations: violations.filter(Boolean) };
295	}
296	
297	// validateResponse(response, opts): the one door every LLM response passes through. Runs parse ->
298	// schema -> retrieval-gate -> quote-match and AND-composes them. Any violation abstains.
299	function validateResponse(response, opts = {}) {
300	  const schema = opts.schema || null;
301	  const allowedSet = toSet(opts.allowedSourceIds);
302	  const sources = opts.sources || {};
303	  const minQuoteLen = Number.isFinite(opts.minQuoteLen) ? opts.minQuoteLen : DEFAULT_MIN_QUOTE_LEN;
304	  const parsed = parseResponse(response);
305	  if (!parsed.ok) return abstain([parsed.violation]);
306	  const value = parsed.value;
307	  const violations = [];
308	  if (schema) violations.push(...validateSchema(value, schema, '$'));
309	  const cites = collectCitations(value);
310	  violations.push(...checkSourceIds(cites.sourceIds, allowedSet));
311	  violations.push(...checkQuotes(cites.quotes, sources, minQuoteLen, allowedSet));
312	  if (violations.length) return abstain(violations);
313	  return { ok: true, value, violations: [] };
314	}
315	
316	// ---------------------------------------------------------------------------------------------------
317	// Calibration CLI (the earn-your-zero contract in eval/calibration-known-bad/run.js).
318	// `node llm/gate.js --calibrate [--json <path>]` replays every p3-llm-*.json fixture. A FINDING is
319	// emitted ONLY when the gate correctly REFUSES the poisoned response (and, if the fixture pins an
320	// expected code, that code is present). Zero findings on a fixture means the gate FAILED to catch its
321	// planted disease, and the calibration runner fails CI (Constitution Rule 4: a zero you did not earn).
322	// ---------------------------------------------------------------------------------------------------
323	
324	function judgeFixture(abs, fx) {
325	  const result = validateResponse(fx.response, {
326	    schema: fx.schema, allowedSourceIds: fx.allowedSourceIds, sources: fx.sources, minQuoteLen: fx.minQuoteLen,
327	  });
328	  const wantCode = (fx.poison && fx.poison.expect_violation) || null;
329	  const codeHit = !wantCode || (result.violations || []).some((v) => v.code === wantCode);
330	  if (result.ok === false && codeHit) {
331	    return { file: abs, line: 1, rule: 'llm-gate-reject', message: 'correctly refused poisoned response: ' + ((result.violations || []).map((v) => v.code).join(',') || 'reject') };
332	  }
333	  // The gate WRONGLY ACCEPTED (or refused for the wrong reason): emit NO finding for this fixture, so
334	  // eval/calibration-known-bad/run.js sees the fixture uncaught and FAILS (earn-your-zero).
335	  return null;
336	}
337	
338	function runCalibration(fixturesDir) {
339	  const fs = require('fs');
340	  const path = require('path');
341	  const dir = fixturesDir || path.join(__dirname, '..', 'eval', 'calibration-known-bad', 'fixtures');
342	  const findings = [];
343	  const files = fs.readdirSync(dir).filter((f) => /^p3-llm-.*\.json$/.test(f)).sort();
344	  for (const f of files) {
345	    if (!/^[a-z0-9][a-z0-9.-]{0,251}$/i.test(f)) throw new Error('unsafe path component: ' + JSON.stringify(f));
346	    const abs = path.join(dir, f);
347	    const finding = judgeFixture(abs, JSON.parse(fs.readFileSync(abs, 'utf8')));
348	    if (finding) findings.push(finding);
349	  }
350	  return findings;
351	}
352	
353	function calibrateMain(argv) {
354	  const fs = require('fs');
355	  const args = argv.slice(2);
356	  const jsonIdx = args.indexOf('--json');
357	  const jsonPath = jsonIdx !== -1 ? args[jsonIdx + 1] : null;
358	  const findings = runCalibration();
359	  if (jsonPath) fs.writeFileSync(jsonPath, JSON.stringify(findings, null, 2));
360	  process.stdout.write(JSON.stringify({ checker: 'llm-gate', findings }) + '\n');
361	  return 0;
362	}
363	
364	if (require.main === module) {
365	  if (process.argv.includes('--calibrate')) {
366	    process.exit(calibrateMain(process.argv));
367	  } else {
368	    process.stderr.write('llm/gate.js is a library (validateResponse). Only --calibrate is runnable from the CLI.\n');
369	    process.exit(2);
370	  }
371	}
372	
373	module.exports = {
374	  validateResponse,
375	  validateSchema,
376	  collectCitations,
377	  checkSourceIds,
378	  checkQuotes,
379	  normalise,
380	  runCalibration,
381	  DEFAULT_MIN_QUOTE_LEN,
382	};
383

1	'use strict';
2	// llm/router.js - the deterministic provider-routing shell (Constitution Rule 9, Rule 12 gate 5).
3	//
4	// NO NETWORK. Providers are INJECTED async callers; this module owns only ordering, the per-call
5	// hard deadline, the no-retry-storm discipline, and the veto-to-reject quorum. It never opens a
6	// socket, reads a provider key, or names a secret. The real network callers are supplied by the
7	// mint layer (ported from cowork-os src/lib/llm/router.js) and passed in as `providers`.
8	//
9	// A provider is a plain object:
10	//   { name: 'groq-8b', family: 'groq', tier?: 'free'|'paid',
11	//     call: async (task, { signal }) => ({ ok, text, ... }) | throws }
12	// `family` is the INDEPENDENCE key (caution.md C-133: two Groq models are NOT an independent
13	// quorum). `call` does the transport; on failure it may throw or return { ok:false, error }.
14	//
15	// Exports:
16	//   route(task, { providers, deadlineMs, log, validate }) -> a routed response (first success)
17	//   quorum(task, { providers, n, vetoRule, validate, deadlineMs, log }) -> a jury verdict
18	//   orderProviders, distinctFamilyProviders, defaultVeto, FAMILY_ORDER, DEFAULT_DEADLINE_MS
19	//
20	// Design pointers earned by the old estate:
21	//   - E-238 / caution.md C-138: exhausted free tiers once burned 30s x 3 retries x 3 gate attempts
22	//     waiting for answers that were never coming. THIS SHELL DOES NOT RETRY: one attempt per
23	//     provider, then fall over. Retry/backoff, if ever wanted, belongs inside an injected `call`,
24	//     never here, so a storm can never originate in the router.
25	//   - caution.md C-040 / Rule 9: every external step is wrapped in a hard Promise.race deadline.
26	//     `deadlineMs` is a CAP (Rule 8: never a floor - there is no minimum wait anywhere in this file).
27	//   - caution.md C-133 / Rule 12 gate 5: a quorum is drawn from genuinely distinct provider FAMILIES.
28	
29	// Free-first family ranking, ported from the proven chain order in cowork-os src/lib/llm/router.js
30	// (Cloudflare Workers AI -> Groq -> NIM -> Gemini -> ... -> paid last). This is the ONE place the
31	// order lives; callers may pass providers in any order and orderProviders() re-imposes free-first.
32	const FAMILY_ORDER = ['cloudflare', 'groq', 'nim', 'gemini', 'deepseek', 'perplexity', 'openai', 'qwen', 'anthropic'];
33	const PAID_FAMILIES = new Set(['deepseek', 'perplexity', 'openai', 'qwen', 'anthropic']);
34	
35	// A short per-call cap by default. The old estate's 30s+ per-provider waits were the hang vector
36	// (caution.md C-040/C-138); a routed classification/adjudication call is bounded to seconds.
37	const DEFAULT_DEADLINE_MS = 9000;
38	
39	// assertDeadline(ms): a budget cap must be a positive finite number. A misconfigured cap must SHOUT,
40	// not silently degrade (caution.md C-025: sub-floor budgets throw at the boundary, never pass quietly).
41	function assertDeadline(ms) {
42	  if (typeof ms !== 'number' || !Number.isFinite(ms) || ms <= 0) {
43	    throw new Error('llm/router: deadlineMs must be a positive finite number, got ' + JSON.stringify(ms));
44	  }
45	}
46	
47	// familyRank(p): the free-first index of a provider's family (unknown families sort last-but-stable).
48	function familyRank(p) {
49	  const idx = FAMILY_ORDER.indexOf(String((p && p.family) || ''));
50	  return idx === -1 ? FAMILY_ORDER.length : idx;
51	}
52	
53	// providerTier(p): 'free' unless the provider declares 'paid' or belongs to a known paid family.
54	function providerTier(p) {
55	  if (p && (p.tier === 'paid' || p.tier === 'free')) return p.tier;
56	  return PAID_FAMILIES.has(String((p && p.family) || '')) ? 'paid' : 'free';
57	}
58	
59	// orderProviders(list): stable free-first ordering (free before paid, then family rank, then the
60	// caller's original index). Pure; returns a new array and never mutates the input.
61	function orderProviders(list) {
62	  const arr = Array.isArray(list) ? list.slice() : [];
63	  return arr
64	    .map((p, idx) => ({ p, idx }))
65	    .sort((a, b) => {
66	      const ta = providerTier(a.p) === 'paid' ? 1 : 0;
67	      const tb = providerTier(b.p) === 'paid' ? 1 : 0;
68	      if (ta !== tb) return ta - tb;
69	      const fa = familyRank(a.p);
70	      const fb = familyRank(b.p);
71	      if (fa !== fb) return fa - fb;
72	      return a.idx - b.idx;
73	    })
