77	// distinctFamilyProviders(ordered, n): the first provider of each distinct family, up to n. This is
78	// the structural independence guarantee for a quorum (caution.md C-133): two models from the same
79	// family can never both sit on the jury.
80	function distinctFamilyProviders(ordered, n) {
81	  const seen = new Set();
82	  const jurors = [];
83	  for (const p of ordered) {
84	    const fam = String((p && p.family) || '');
85	    if (seen.has(fam)) continue;
86	    seen.add(fam);
87	    jurors.push(p);
88	    if (jurors.length >= n) break;
89	  }
90	  return jurors;
91	}
