129	// callProvider(provider, task, deadlineMs, validate, log): one deadline-bounded attempt at one
130	// provider. Returns { ok, value?, text?, response?, record }. `record` is always populated for the
131	// attempts ledger (Part B Rule 9: log every routing decision). A structural `validate` (llm/gate.js)
132	// turns a transport success into a routing success ONLY when the response also passes the gate - a
133	// fluent-but-hallucinated answer must not win just because the socket returned 200.
134	async function callProvider(provider, task, deadlineMs, validate, log) {
135	  const t0 = Date.now();
136	  const controller = new AbortController();
137	  // withDeadline converts BOTH a fulfilment and a rejection into a resolved result, so a throwing
138	  // injected caller is a first-class value here (raced.error), never an uncaught throw - no catch
139	  // is needed, and a rejection cleanly falls the chain OVER to the next provider (fail-closed system).
140	  const raced = await withDeadline(
141	    Promise.resolve().then(() => provider.call(task, { signal: controller.signal })),
142	    deadlineMs,
143	    () => controller.abort()
144	  );
145	  const ms = Date.now() - t0;
146	  const base = { provider: provider.name, family: provider.family, ms };
147	  if (raced.timedOut) return finalize(base, 'timeout', null, log);
148	  if (raced.error !== undefined) return finalize(base, 'threw:' + errText(raced.error), null, log);
149	  const interp = interpretResponse(raced.value);
150	  if (!interp.ok) return finalize(base, interp.error, null, log);
151	  if (typeof validate === 'function') return validated(base, interp, raced.value, validate, log);
152	  return { ok: true, text: interp.text, response: raced.value, record: logged(base, 'ok', log) };
153	}
154	
155	// validated(base, interp, raw, validate, log): apply the injected structural gate to a transport
156	// success. A rejection is recorded as 'gate_reject' and treated as a provider failure (fall over).
157	function validated(base, interp, raw, validate, log) {
158	  const verdict = validate(raw != null ? raw : interp.text);
159	  if (verdict && verdict.ok) {
160	    return { ok: true, value: verdict.value, text: interp.text, response: raw, record: logged(base, 'ok', log) };
161	  }
162	  const reason = 'gate_reject:' + firstViolationCode(verdict);
163	  return finalize(base, reason, null, log);
164	}
165	
166	// firstViolationCode(verdict): the leading violation code from a gate result, for the attempt log.
167	function firstViolationCode(verdict) {
168	  const v = verdict && Array.isArray(verdict.violations) ? verdict.violations[0] : null;
169	  return (v && v.code) ? v.code : 'invalid';
170	}
171	
172	// finalize(base, outcome, value, log): shape a FAILED attempt and log it.
173	function finalize(base, outcome, value, log) {
174	  return { ok: false, value, record: logged(base, outcome, log) };
175	}
176	
177	// logged(base, outcome, log): stamp the outcome on the attempt record and emit it to the injected
178	// sink if one was supplied (the router never writes anywhere itself).
179	function logged(base, outcome, log) {
180	  const record = { provider: base.provider, family: base.family, outcome, ms: base.ms };
181	  // FAIL-OPEN: a caller-supplied log sink must never break routing; a throwing sink is swallowed
182	  // here so an observability fault cannot fail a mint. The routing decision itself is unaffected.
183	  if (typeof log === 'function') { try { log(record); } catch (_e) { /* FAIL-OPEN: log sink faults are non-fatal */ } }
184	  return record;
185	}
186	
187	// route(task, opts): try providers free-first, one deadline-bounded attempt each, and return the
188	// first success. `validate` (llm/gate.js) is optional but recommended: it makes a hallucinated
189	// response lose to the next provider instead of winning. Exhaustion returns an abstain, never a guess.
190	async function route(task, opts = {}) {
191	  const { providers = [], deadlineMs = DEFAULT_DEADLINE_MS, log = null, validate = null } = opts;
192	  assertDeadline(deadlineMs);
193	  const ordered = orderProviders(providers);
194	  const attempts = [];
195	  if (!ordered.length) return { ok: false, reason: 'no_providers', text: '', attempts };
196	  for (const provider of ordered) {
197	    const outcome = await callProvider(provider, task, deadlineMs, validate, log);
198	    attempts.push(outcome.record);
199	    if (outcome.ok) {
200	      return {
201	        ok: true, provider: outcome.record.provider, family: outcome.record.family,
202	        text: outcome.text, value: outcome.value, response: outcome.response, attempts,
203	      };
204	    }
205	  }
206	  return { ok: false, reason: 'all_providers_exhausted', text: '', attempts };
207	}
208	
209	// defaultVeto(vote): the standing veto polarity for a findings jury (Part A Pattern 5: weak judges
210	// have high true-positive but very low true-negative rates, so a REJECTION is the trustworthy signal
211	// and veto-to-reject is the correct polarity). A juror vetoes when it declares an explicit veto, or
212	// when its validated verdict is anything other than the affirmative 'violation'.
213	function defaultVeto(vote) {
214	  const v = (vote && vote.value) || {};
215	  if (v.veto === true) return { veto: true, reason: String(v.reason || 'explicit_veto').slice(0, 80) };
216	  if (typeof v.verdict === 'string' && v.verdict !== 'violation') {
217	    return { veto: true, reason: 'verdict=' + v.verdict };
218	  }
219	  return { veto: false };
220	}
221	
222	// firstVeto(valid, vetoRule): the first juror to veto, or null when the jury is unanimous.
223	function firstVeto(valid, vetoRule) {
224	  for (const vote of valid) {
225	    const r = vetoRule(vote);
226	    if (r && r.veto) return { provider: vote.provider, reason: String(r.reason || 'veto') };
227	  }
228	  return null;
229	}
230	
231	// collectVotes(jurors, task, deadlineMs, validate, log): call each juror, gate.js-validate each
232	// response BEFORE it may vote (Rule 12: gates 1-4 run per response), and return the vote ledger.
233	async function collectVotes(jurors, task, deadlineMs, validate, log) {
234	  const votes = [];
235	  for (const juror of jurors) {
236	    const outcome = await callProvider(juror, task, deadlineMs, validate, log);
237	    if (outcome.ok) votes.push({ provider: juror.name, family: juror.family, value: outcome.value != null ? outcome.value : { text: outcome.text } });
238	    else votes.push({ provider: juror.name, family: juror.family, value: null, invalid: outcome.record.outcome });
239	  }
240	  return votes;
241	}
