243	// quorum(task, opts): the diverse-jury, veto-to-reject gate for P0/P1 findings (Rule 12 gate 5).
244	//   - A CURATED fact (task.curated: an in-set catalogue assertion) is IMMUNE: the jury has no
245	//     authority to veto it (caution.md C-131 - the LLM once vetoed the SRA off an SRA-regulated firm).
246	//   - A finding needs n jurors from n DISTINCT families; too few independent families => fail-closed
247	//     reject (an unadjudicated P0/P1 is demoted to needs-review by the consumer, caution.md C-083).
248	//   - Every response is gate.js-validated before voting; too few valid votes => fail-closed reject.
249	//   - Any single veto rejects; only a unanimous, un-vetoed jury accepts.
250	async function quorum(task, opts = {}) {
251	  const { providers = [], n = 2, vetoRule = defaultVeto, validate = null, deadlineMs = DEFAULT_DEADLINE_MS, log = null } = opts;
252	  assertDeadline(deadlineMs);
253	  if (typeof n !== 'number' || !Number.isInteger(n) || n < 1) throw new Error('llm/router: quorum n must be a positive integer, got ' + JSON.stringify(n));
254	  if (task && task.curated) {
255	    return { ok: true, verdict: 'immune', votes: [], reason: 'curated fact: the jury may never veto a catalogue fact (Rule 12 gate 5 immunity)' };
256	  }
257	  const jurors = distinctFamilyProviders(orderProviders(providers), n);
258	  if (jurors.length < n) {
259	    return { ok: false, verdict: 'reject', reason: 'insufficient_independent_families:' + jurors.length + '<' + n, votes: [] };
260	  }
261	  const votes = await collectVotes(jurors, task, deadlineMs, validate, log);
262	  const valid = votes.filter((v) => v.value != null);
263	  if (valid.length < n) return { ok: false, verdict: 'reject', reason: 'insufficient_valid_votes:' + valid.length + '<' + n, votes };
264	  const veto = firstVeto(valid, vetoRule);
265	  if (veto) return { ok: false, verdict: 'reject', reason: 'veto[' + veto.provider + ']:' + veto.reason, votes };
266	  return { ok: true, verdict: 'accept', votes };
267	}
268	
269	if (require.main === module) {
270	  process.stderr.write('llm/router.js is a library (route/quorum). Providers are injected; it makes no network calls.\n');
271	  process.exit(2);
272	}
