323	  const manyDecisions = Array.from({ length: 13 }, (_, i) => `if (a${i}) { y(); }`).join(' ');
324	  const longBody = Array.from({ length: 65 }, (_, i) => `  const v${i} = ${i};`).join('\n');
325	  const src = [
326	    'function tooLong(a, b, c, d, e, f) {',
327	    longBody,
328	    '  ' + nested,
329	    '  ' + manyDecisions,
330	    '  return a + b + c + d + e + f;',
331	    '}',
332	    '',
333	    'const clean = (x) => x + 1;',
