336	  const r = scanContent('selftest.js', src);
337	  const kinds = new Set(r.violations.map((v) => v.kind));
338	  const functionCaps = ['long-function', 'deep-nesting', 'high-branching', 'too-many-params'];
339	  const wantFunctionCaps = functionCaps.every((k) => kinds.has(k));
