39	 *   toFindings     (violations) -> normaliser-shaped findings
40	 *   scanDirs       directories for the normal scan
41	 *   summary        (result) -> one summary line for the normal scan
42	 *   calibrateSummary (result) -> one summary line for the calibrate scan
43	 *   violationLine  (v) -> one line per violation
44	 * }
45	 */
46	function runGateCli(opts) {
47	  const { calibrate, writeJson } = parseGateArgs(process.argv);
48	
49	  const st = opts.selfTest();
50	  if (!st.pass) {
51	    console.error(opts.name + ' SELF-TEST FAILED: ' + st.detail);
52	    console.error('The gate cannot see the class it exists to catch. Every zero it reports is unearned.');
53	    process.exit(2);
54	  }
55	
56	  if (calibrate) {
