1	'use strict';
2	/**
3	 * acorn-scan.js - the shared source-tree walk for the acorn domain gates (budget-caps, host-parse).
4	 *
5	 * Both gates walk the same engine source dirs and apply their OWN per-file detector; only the traversal is
6	 * identical. That traversal lived byte-for-byte in each gate (a jscpd clone). It is extracted here so there
7	 * is ONE copy: each gate keeps its own scanContent(relPath, src) -> { violations } (its detection door) and
8	 * passes it in. Pure over its inputs; the only effect is reading files off disk via listJsFiles.
9	 */
10	const fs = require('fs');
11	const path = require('path');
12	
13	const { ROOT } = require('../lib/gate-cli');
14	const { listJsFiles } = require('../lib/fswalk');
15	
16	// scanTreeWith(dirs, skipDirs, scanContent) -> { violations, scanned }. Walks every non-test .js file under
17	// each dir (skipping skipDirs), applies scanContent to its source, and aggregates the violations. Test
18	// files are skipped (skipTests) so a gate never flags its own calibration fixtures' consuming tests.
19	function scanTreeWith(dirs, skipDirs, scanContent) {
20	  const violations = [];
21	  let scanned = 0;
22	  for (const dir of dirs) {
23	    const absDir = path.isAbsolute(dir) ? dir : path.join(ROOT, dir);
24	    for (const abs of listJsFiles(absDir, { skipDirs, skipTests: true })) {
25	      scanned++;
26	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
27	      violations.push(...scanContent(rel, fs.readFileSync(abs, 'utf8')).violations);
28	    }
29	  }
30	  return { violations, scanned };
31	}
32	
33	module.exports = { scanTreeWith };
