1	'use strict';
2	/**
3	 * The one file walker for the tool fleet. one-door, swallow-gate and the sweep collectors all walk the tree
4	 * through this door; a second walker is exactly the clone class jscpd exists to catch.
5	 */
6	const fs = require('fs');
7	const path = require('path');
8	
9	const DEFAULT_SKIP = /^(node_modules|\.git|out)$/;
10	
11	/**
12	 * List .js/.mjs/.cjs files under absDir.
13	 * opts.skipDirs   regex of directory NAMES to skip (default: node_modules, .git, out)
14	 * opts.skipTests  when true, skip *.test.js files and tests/ directories
15	 */
16	function listJsFiles(absDir, opts) {
17	  const o = opts || {};
18	  const skipDirs = o.skipDirs || DEFAULT_SKIP;
19	  const files = [];
20	  if (!fs.existsSync(absDir)) return files;
21	  (function walk(d) {
22	    for (const e of fs.readdirSync(d, { withFileTypes: true })) {
23	      const p = path.join(d, e.name);
24	      if (e.isDirectory()) {
25	        if (skipDirs.test(e.name)) continue;
26	        if (o.skipTests && /^tests?$/.test(e.name)) continue;
27	        walk(p);
28	      } else if (/\.(js|mjs|cjs)$/.test(e.name)) {
29	        if (o.skipTests && /\.test\.[mc]?js$/.test(e.name)) continue;
30	        files.push(p);
31	      }
32	    }
33	  })(absDir);
34	  return files;
35	}
36	
37	module.exports = { listJsFiles };
