263	// payload (a bare array, or {findings:[...]}), else null.
264	function findingsFromParsed(parsed) {
265	  if (Array.isArray(parsed)) return parsed;
266	  if (parsed && Array.isArray(parsed.findings)) return parsed.findings;
267	  return null;
268	}
