283	  const contract = require(path.join(REPO_ROOT, 'payload', 'contract'));
284	  const payload = JSON.parse(fs.readFileSync(fixtureAbs, 'utf8'));
285	  const missing = contract.validatePayload(payload);
286	  return missing.map((m) => ({ file: fixtureAbs, rule: 'payload-contract', message: `missing: ${m}` }));
