303	// runInternalCalibration(cal, fixtureAbs) -> {entries, failed, skipped: 0}. The "internal": true
304	// calibration (payload-contract) runs payload/contract's validatePayload() directly rather than
305	// spawning an external checker.
306	function runInternalCalibration(cal, fixtureAbs) {
307	  const entries = [];
308	  let failed = 0;
309	  try {
310	    const findings = runInternalPayloadContract(fixtureAbs[0]);
311	    if (findings.length > 0) {
312	      entries.push({ name: cal.name, status: 'PASS', detail: `${findings.length} finding(s) on the fixture (e.g. ${findings[0].message})` });
313	    } else {
314	      entries.push({ name: cal.name, status: 'FAIL', detail: 'validatePayload() returned an EMPTY missing list on a deliberately incomplete payload - the contract gate is broken' });
315	      failed++;
316	    }
317	  } catch (e) {
318	    entries.push({ name: cal.name, status: 'FAIL', detail: `internal check errored: ${e.message}` });
319	    failed++;
320	  }
321	  return { entries, failed, skipped: 0 };
