324	// missingCheckerResult(cal, strict) -> the {entries,failed,skipped} result when no checker under
325	// tools/ was found for this calibration: FAIL in --strict mode (a fixture without a live checker
326	// is an unearned zero), SKIPPED otherwise (tools/ agent has not landed this gate yet).
327	function missingCheckerResult(cal, strict) {
328	  const detail = `no checker found (looked at: ${cal.checkerCandidates.join(', ')})`;
329	  if (strict) {
330	    return { entries: [{ name: cal.name, status: 'FAIL', detail: `${detail} - strict mode: a fixture without a live checker is an unearned zero` }], failed: 1, skipped: 0 };
331	  }
332	  return { entries: [{ name: cal.name, status: 'SKIPPED', detail: `${detail} - tools/ agent has not landed this gate yet; CI must flip to --strict when it does` }], failed: 0, skipped: 1 };
333	}
