383	// report({strict, results, failed, skipped, asJson}) -> prints the run's summary in --json or
384	// human form, unchanged from the original inline block in main() (params bundled into one object;
385	// not exported, so the call site below is the only caller to update).
386	function report({ strict, results, failed, skipped, asJson }) {
387	  if (asJson) {
388	    console.log(JSON.stringify({ strict, results, failed, skipped }, null, 2));
389	    return;
390	  }
391	  console.log('calibration-known-bad: the earn-your-zero gate');
392	  for (const r of results) console.log(`  ${r.status.padEnd(7)} ${r.name}: ${r.detail}`);
393	  if (failed > 0) {
394	    console.log(`RESULT: FAIL - ${failed} gate(s) did not catch their seeded known-bad fixture. A gate that misses planted disease is reporting worthless greens.`);
395	  } else if (skipped > 0) {
396	    console.log(`RESULT: OK with ${skipped} SKIPPED - external checkers not landed yet. Flip CI to --strict once tools/ lands.`);
397	  } else {
398	    console.log('RESULT: OK - every gate caught its fixture.');
399	  }
400	}
