323	    ran: false, llm_available: false, timed_out: false, total,
324	    observed_fact: 0, register_fact: 0, rejected: 0, text_derived: 0,
325	    violation: 0, needs_review: 0, pass: 0, batches: [],
326	  };
327	}
328	function tallyState(report, state) {
329	  if (state === 'violation') report.violation++;
330	  else if (state === 'pass') report.pass++;
