3	// tools/sweep/collect-workflows.js - parse every .github/workflows/*.yml and fail on YAML errors.
4	//
5	// Why this lane exists (caution.md C-202, PR #3): an unquoted ": " inside a step name silently
6	// broke ci.yml. GitHub does not fail a push for an unparsable workflow - the workflow's checks
7	// simply VANISH from the check-run list, and a reviewer scanning "all present checks are green"
8	// reads a gutted run as a full pass. A broken workflow must therefore be a LOCAL P0 finding.
9	//
10	// Parser: python3 + PyYAML (present on macOS dev machines and ubuntu-latest runners). If python3
11	// or PyYAML is unavailable this lane exits 2 (broken tool) rather than reporting an unearned zero.
12	const fs = require('fs');
13	const path = require('path');
14	const { spawnSync, execFileSync } = require('child_process');
15	
16	const ROOT = path.resolve(__dirname, '..', '..');
17	const WF_DIR = path.join(ROOT, '.github', 'workflows');
18	
19	// discoverWorkflowFiles(dir) -> { ok: true, files } when the directory exists and holds at least one
20	// YAML workflow, otherwise { ok: false, message }. Both failure branches are the SAME protected
21	// class: deleting every workflow (or the whole directory) makes the required checks VANISH from
22	// GitHub rather than fail (caution.md C-202), so an empty/missing set is broken configuration, never
23	// a clean zero. Kept pure and exported so the fail-closed contract is unit-testable.
24	function discoverWorkflowFiles(dir) {
25	  // A missing directory is checked explicitly (no catch): an absent .github/workflows is the vanished-
26	  // check failure, not "nothing to do". If the directory exists but is unreadable, readdirSync throws
27	  // and the tool aborts with a non-zero exit - still fail closed, never a false pass.
28	  if (!fs.existsSync(dir)) {
29	    return { ok: false, message: '.github/workflows is missing - deleting workflows makes required checks vanish from GitHub rather than fail. Exit 1 (broken configuration).' };
30	  }
31	  const files = fs.readdirSync(dir).filter((f) => /\.ya?ml$/.test(f)).sort();
32	  if (files.length === 0) {
33	    return { ok: false, message: '0 workflow files under .github/workflows - the required-check set is empty, the vanished-check failure this gate exists to catch. Exit 1.' };
34	  }
35	  return { ok: true, files };
36	}
37	
38	function main() {
39	  const discovered = discoverWorkflowFiles(WF_DIR);
40	  if (!discovered.ok) {
41	    console.error('collect-workflows: ' + discovered.message);
42	    return 1;
43	  }
44	  const files = discovered.files;
45	
46	  try {
47	    execFileSync('python3', ['-c', 'import yaml'], { stdio: 'ignore' });
48	  } catch (_e) {
49	    // FAIL-OPEN is not acceptable for a parser gate: no parser means no earned zero.
50	    console.error('collect-workflows: python3+PyYAML unavailable - cannot earn a zero. Exit 2 (broken tool).');
51	    return 2;
52	  }
