65	  }
66	  if (bad > 0) {
67	    console.error('collect-workflows: ' + bad + ' workflow file(s) do not parse. A broken workflow makes its checks VANISH from GitHub, not fail - this is a P0 finding.');
68	    return 1;
69	  }
70	  console.log('collect-workflows: all ' + files.length + ' workflow files parse.');
71	  return 0;
72	}
