59	// Declared `evidence_kind` synonyms -> the canonical three. Presence and absence both canonicalise to
60	// `absence` (the adjudicated text class): a matched quote still needs the model to rule out the "firm
61	// writing ABOUT a topic is not committing it" false positive, exactly as an absence claim does.
62	const DECLARED_TO_KIND = new Map([
63	  ['observation', 'observation'], ['observed', 'observation'], ['observed_fact', 'observation'],
64	  ['observed-behaviour', 'observation'], ['observed_behaviour', 'observation'], ['observed_in_browser', 'observation'],
65	  ['behaviour', 'observation'], ['browser', 'observation'],
66	  ['register', 'register'], ['register-fact', 'register'], ['register_fact', 'register'],
67	  ['public_register_checked', 'register'], ['register_row', 'register'],
68	  ['absence', 'absence'], ['document-absence', 'absence'], ['document_absence', 'absence'],
69	  ['presence', 'absence'], ['document-presence', 'absence'], ['document_presence', 'absence'],
70	  ['text', 'absence'], ['text-derived', 'absence'],
71	]);
72	
73	const KINDS = new Set(['observation', 'absence', 'register']);
74	const BYPASS_KINDS = new Set(['observation', 'register']); // observations + register rows skip the LLM
75	
76	function artifactTypeOf(candidate) {
77	  const a = candidate && candidate.artifact;
78	  return a && typeof a.type === 'string' ? a.type.toLowerCase().trim() : '';
79	}
80	
81	// Port-compat: the old estate carried the observed/register signal inside `absence_evidence.state`
82	// (E-272 `_observedFact`). We still honour that shape so a ported candidate is classified correctly.
83	function legacyObservedKind(candidate) {
84	  const ae = candidate && candidate.absence_evidence;
85	  const st = ae && typeof ae.state === 'string' ? ae.state.toLowerCase().trim() : '';
86	  if (st === 'observed_in_browser') return 'observation';
87	  if (st === 'public_register_checked') return 'register';
88	  return null;
89	}
90	
91	// artifactKindOf(candidate) -> the kind the ARTIFACT establishes, or null when no artifact is
92	// recognisable (a Rule-3 reject: no artifact, no breach). Never throws.
93	function artifactKindOf(candidate) {
94	  const t = artifactTypeOf(candidate);
95	  if (OBSERVED_ARTIFACT_TYPES.has(t)) return 'observation';
96	  if (REGISTER_ARTIFACT_TYPES.has(t)) return 'register';
97	  if (TEXT_ARTIFACT_TYPES.has(t)) return 'absence';
98	  const legacy = legacyObservedKind(candidate);
99	  if (legacy) return legacy;
100	  // No typed artifact: a verbatim quote or an absence record is still the adjudicated text class.
101	  if (candidate && (candidate.evidence_quote || candidate.absence_evidence)) return 'absence';
102	  return null;
103	}
104	
105	// declaredKindOf(candidate) -> the canonical kind the candidate CLAIMS via `evidence_kind`, or null
106	// when it declares nothing (no claim = nothing to masquerade; the artifact governs).
107	function declaredKindOf(candidate) {
108	  const raw = candidate && candidate.evidence_kind;
109	  if (typeof raw !== 'string') return null;
110	  return DECLARED_TO_KIND.get(raw.toLowerCase().trim()) || null;
111	}
112	
113	function classification(kind, bypass, valid, reason) {
114	  return { kind, bypass, valid, reason: reason || null };
115	}
116	
117	/**
118	 * classifyEvidenceKind(candidate) -> { kind, bypass, valid, reason }
119	 *   kind    'observation' | 'absence' | 'register' - the resolved evidence kind (task contract).
120	 *   bypass  true for observation + register (skip LLM adjudication, ship as an observed fact);
121	 *           false for absence (must be adjudicated by the model).
122	 *   valid   false when the candidate MASQUERADED its kind (declared != artifact) or carries no
123	 *           deterministic artifact at all - the adjudicator quarantines it to needs-review.
124	 *   reason  a human-readable cause when valid is false (for the report + stage manifest), else null.
125	 *
126	 * The artifact is ground truth. A declared kind is only ever a cross-check against it; on any
127	 * disagreement the candidate is rejected (never silently trusted, never allowed to bypass).
128	 */
129	function classifyEvidenceKind(candidate) {
130	  const artifactKind = artifactKindOf(candidate);
131	  const declared = declaredKindOf(candidate);
132	  // Rule 3: no recognised artifact means this cannot be a breach input. Quarantine (never bypass).
133	  if (artifactKind === null) {
134	    const reason = declared
135	      ? ('declared "' + declared + '" but no deterministic artifact backs it (Rule 3)')
136	      : 'no deterministic artifact - no artifact, no breach (Rule 3)';
137	    return classification('absence', false, false, reason);
138	  }
139	  // Anti-masquerade (C-084 / C-085): the artifact wins; a declared kind that disagrees is rejected.
140	  if (declared && declared !== artifactKind) {
141	    return classification(artifactKind, false, false,
142	      'kind mismatch: declared "' + declared + '" but the artifact establishes "' + artifactKind + '"');
143	  }
144	  return classification(artifactKind, BYPASS_KINDS.has(artifactKind), true, null);
145	}
146	
147	module.exports = {
148	  classifyEvidenceKind,
149	  artifactKindOf,
150	  declaredKindOf,
151	  KINDS,
152	  BYPASS_KINDS,
153	  OBSERVED_ARTIFACT_TYPES,
154	  REGISTER_ARTIFACT_TYPES,
155	  TEXT_ARTIFACT_TYPES,
156	};
