const useAcorn = Boolean(acorn) && !FORCE_REFUSE;

// ── tiny helpers ────────────────────────────────────────────────────────────────────────────────────
function isMetaKey(k) { return k === 'loc' || k === 'start' || k === 'end' || k === 'range'; }
