// '=' to a member, or an arithmetic/bitwise compound, is an accumulator mutation (M1, always flagged).
function handleAssign(node, ctx) {
  if (!inFunction(ctx)) return;
  const name = rootIdent(node.left);
  if (!isModuleTarget(name, ctx)) return;
  if (ARITH_COMPOUND.has(node.operator)) {
    flag(ctx, node, name, 'module-accumulator', 'module-scope binding "' + name + '" is compound-mutated (' + node.operator + ') from a function - a per-audit accumulator (C-153)');
    return;
  }
  if (node.operator !== '=') return; // logical compound (||= &&= ??=) is idempotent memoisation - exempt
  if (node.left.type === 'MemberExpression') {
    flag(ctx, node, name, 'module-accumulator', 'a property of module-scope object "' + name + '" is written from a function - per-audit mutation of shared state (C-153)');
    return;
  }
  const fn = topFn(ctx);
  if (fn.isIife || fn.guarded.has(name) || identsIn(node.right).has(name)) return; // module-init / guarded write-once / idempotent self-ref
  flag(ctx, node, name, 'module-reassign', 'module-scope binding "' + name + '" is reassigned from a function without a write-once guard - per-audit state that leaks between builds (C-153); use a per-invocation state object');
}

function detectWrite(node, ctx) {
  if (node.type === 'UpdateExpression') handleUpdate(node, ctx);
  else if (node.type === 'AssignmentExpression') handleAssign(node, ctx);
  else if (node.type === 'CallExpression') handleMutatingCall(node, ctx);
}

// ── the walk: push a function context on entering a function, so shadowing + IIFE + guard are known ────
function walkChildren(node, ctx) {
  for (const k of Object.keys(node)) { if (!isMetaKey(k)) walk(node[k], ctx); }
}
function walkFunction(node, ctx) {
  ctx.fnStack.push({ node, isIife: ctx.iifes.has(node), local: collectLocalNames(node), guarded: guardReturnBindings(node) });
  walkChildren(node, ctx);
  ctx.fnStack.pop();
}
function walk(node, ctx) {
  if (!node || typeof node !== 'object') return;
  if (Array.isArray(node)) { for (const n of node) walk(n, ctx); return; }
  if (typeof node.type !== 'string') return;
  if (FN_TYPES.has(node.type)) { walkFunction(node, ctx); return; }
  detectWrite(node, ctx);
  walkChildren(node, ctx);
}

function scanContent(relPath, src) {
  if (!useAcorn) throw new Error(relPath + ': acorn unavailable and NO_MODULE_STATE refuses to approximate mutation detection (an under-report is an unearned zero, Constitution Rule 4)');
  let ast;
  try { ast = acorn.parse(src, { ecmaVersion: 'latest', allowHashBang: true, allowReturnOutsideFunction: true, allowAwaitOutsideFunction: true, locations: true }); }
  catch (e) { throw new Error(relPath + ': acorn cannot parse this file: ' + e.message + ' (a parse failure is NOT zero violations)'); }
  const bindings = collectModuleBindings(ast);
  if (bindings.size === 0) return { violations: [] };
  const ctx = { bindings, iifes: collectIifes(ast), relPath, violations: [], fnStack: [] };
  walk(ast, ctx);
  return { violations: ctx.violations };
}

function scanTree(dirs) {
  return scanTreeWith(dirs, SKIP_DIRS, scanContent);
}

function selfTest() {
  if (!useAcorn) {
    let refused = false;
    try { scanContent('selftest.js', 'let n = 0; function f(){ n++; }'); }
    catch (e) { refused = true; /* FAIL-OPEN: the throw is the measured refusal signal (acorn mandatory), captured on purpose. */ }
    return { pass: refused, detail: refused ? 'no-acorn engine correctly REFUSES (exit 2), never a zero' : 'no-acorn engine did not refuse - it must never approximate' };
  }
  const bad = [
    'let n = 0; function f(){ n++; }',                                       // accumulator ++
    'const s = []; function g(x){ s.push(x); }',                             // mutating method on module collection
    'let c = null; function h(v){ c = v; }',                                 // unguarded reassignment
    'let t = 0; function k(x){ t += x; }',                                   // compound accumulator
    'const o = {}; function p(v){ o.total = v; }',                           // property write on module object
  ];
  const good = [
    'let cache = null; function m(){ if (cache) return cache; cache = build(); return cache; }', // guarded write-once
    'let linked = false; (function init(){ linked = true; })();',                                // module-init IIFE
    'function loop(a){ let n = 0; for (const x of a) n++; return n; }',                           // local counter (shadow)
    'let mod = null; function load(){ if (mod) return mod; mod = require("x"); return mod; }',    // require cache (guarded)
    'const FROZEN = Object.freeze({ a: 1 }); function r(){ return FROZEN.a; }',                    // frozen const
    'let once = null; function o(v){ once = once || v; return once; }',                           // idempotent self-ref
  ];
  const badOk = bad.every((s) => scanContent('t.js', s).violations.length === 1);
  const goodOk = good.every((s) => scanContent('t.js', s).violations.length === 0);
  return {
    pass: badOk && goodOk,
    detail: (badOk && goodOk)
      ? 'catches module-scope accumulators (++/+=/.push/property-write) and unguarded reassignments; clears guarded memoisation, IIFE init, local counters, require caches, frozen consts and idempotent self-refs (engine: acorn)'
      : 'FAILED: badOk=' + badOk + ' goodOk=' + goodOk,
  };
}

function toFindings(violations) {
  return violations.map((v) => ({
    tool: 'no-module-state', ruleId: 'no-module-state/' + v.kind, file: v.file,
    startLine: v.line, endLine: v.line, level: 'error', message: v.message, snippet: v.name,
  }));
}

function main() {
  try {
    runGateCli({
      name: 'no-module-state',
      selfTest,
      scan: scanTree,
      toFindings,
      scanDirs: SCAN_DIRS,
      summary: (r) => r.scanned + ' files, ' + r.violations.length + ' mutable module-scope-state violation(s) (engine: ' + (useAcorn ? 'acorn' : 'refuse') + ')',
      calibrateSummary: (r) => r.scanned + ' fixture files, ' + r.violations.length + ' seeded module-scope mutation(s) found',
      violationLine: (v) => 'MODULE-STATE [' + v.kind + '] ' + v.file + ':' + v.line + '  ' + v.message,
    });
  } catch (e) {
    // FAIL-CLOSED: an acorn refusal or a parse failure is a broken-tool state (exit 2), never a zero.
    console.error('no-module-state REFUSES: ' + e.message);
    process.exit(2);
  }
}

if (require.main === module) main();

module.exports = { scanContent, scanTree, selfTest, toFindings, collectModuleBindings };

'use strict';
// p3-gate-module-state.js - SEEDED KNOWN-BAD for tools/no-module-state/check.js (caution.md C-153).
// The _WARN / _SWARN / _lastDomain singletons below are the exact disease: module-scope state mutated
// per audit from a function, so it leaks into the next build. The gate MUST catch each mutation; a run
// that reports zero here means the gate cannot see the class it exists to catch (Rule 4).
//
// This file is DATA (a calibration fixture), never wired into the mint. loadOnce is the clean control:
// a guarded write-once memoisation must NOT be flagged.

let _WARN = 0;         // a per-audit counter that is never reset between builds
const _SWARN = [];     // a mutable module-scope accumulator (the C-153 _SWARN singleton)
let _lastDomain = null; // reassigned per audit from a function

// BAD: increments and pushes onto module-scope state - warning counts are wrong for audit two onward.
function recordWarning(msg) {
  _WARN++;
  _SWARN.push(msg);
}

// BAD: an unguarded reassignment of module-scope state from a function.
function setDomain(domain) {
  _lastDomain = domain;
}

// CLEAN CONTROL: a guarded write-once memoisation of an immutable value - must NOT be flagged.
let _built = null;
function loadOnce() {
  if (_built) return _built;
  _built = { ready: true };
  return _built;
}

module.exports = { recordWarning, setDomain, loadOnce };

'use strict';
// check.test.js - the C-153 no-module-state gate. Exercised as a node:test module (not only via
// --calibrate) so npm test proves it still catches the seeded _WARN/_SWARN fixture and clears the
// benign singletons (require caches, guarded memoisation, module-init IIFE).

const test = require('node:test');
const assert = require('node:assert');
const fs = require('node:fs');
const path = require('node:path');

const gate = require('./check.js');

const ROOT = path.join(__dirname, '..', '..');
const FIXTURE = path.join(ROOT, 'eval', 'calibration-known-bad', 'fixtures', 'p3-gate-module-state.js');

test('self-test is earned: catches accumulators/reassignments, clears the benign singletons', () => {
  const r = gate.selfTest();
  assert.equal(r.pass, true, r.detail);
});

test('the seeded _WARN/_SWARN/_lastDomain disease is caught (3 mutations), guarded cache is not', () => {
  const v = gate.scanContent('p3-gate-module-state.js', fs.readFileSync(FIXTURE, 'utf8')).violations;
  const names = v.map((x) => x.name).sort();
  assert.deepEqual(names, ['_SWARN', '_WARN', '_lastDomain'], 'exactly the three leaking bindings, not the guarded _built cache');
});

test('a module-scope counter incremented from a function is flagged', () => {
  assert.equal(gate.scanContent('t.js', 'let n = 0; function f(){ n++; }').violations.length, 1);
});

test('a mutating method on a module-scope collection is flagged', () => {
  assert.equal(gate.scanContent('t.js', 'const s = []; function g(x){ s.push(x); }').violations.length, 1);
  assert.equal(gate.scanContent('t.js', 'const m = {}; function g(k, v){ m[k] = v; }').violations.length, 1, 'property write on a module object literal');
});

test('a guarded write-once memoisation is NOT flagged (the loadVocabulary shape)', () => {
  const src = 'let cache = null; function load(){ if (cache) return cache; cache = require("x"); return cache; }';
  assert.equal(gate.scanContent('t.js', src).violations.length, 0);
});

test('a module-load-time IIFE write is NOT flagged (the linkVocabulary shape)', () => {
  const src = 'let linked = false; let failure = null; (function link(){ failure = "x"; linked = true; })();';
  assert.equal(gate.scanContent('t.js', src).violations.length, 0);
});

test('a local counter that shadows nothing at module scope is NOT flagged', () => {
  assert.equal(gate.scanContent('t.js', 'function loop(a){ let n = 0; for (const x of a) n += 1; return n; }').violations.length, 0);
});

test('a frozen const and a plain require const are NOT tracked as mutable bindings', () => {
  assert.equal(gate.scanContent('t.js', 'const F = Object.freeze({a:1}); function r(){ return F.a; }').violations.length, 0);
  assert.equal(gate.scanContent('t.js', 'const dep = require("x"); function u(){ return dep.y(); }').violations.length, 0);
});

test('the real facts/ and evidence/ module-scope caches are clean (guarded/IIFE/require)', () => {
  for (const rel of ['facts/sector.js', 'facts/capabilities.js', 'evidence/registers/lib/name-match.js']) {
    const src = fs.readFileSync(path.join(ROOT, rel), 'utf8');
    assert.equal(gate.scanContent(rel, src).violations.length, 0, rel + ' must be module-state clean');
  }
});

test('a malformed source is fail-closed (throws), never counted as zero violations', () => {
  assert.throws(() => gate.scanContent('bad.js', 'let ( { ) not js'));
});

