1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * SWALLOW-GATE: no failure may report success.
5	 *
6	 * A swallowed exception is how a failure reports success. The old estate was burned by this class repeatedly:
7	 * a coherence gate found 55 silent catches that an earlier regex had reported as 0. Every catch block in this
8	 * repo must do one of three things:
9	 *
10	 *   1. RETHROW            throw inside the catch body
11	 *   2. RECORD             call a recorder: _warn / warn / record* / addWarning / manifest.record /
12	 *                         logger.warn|error / console.warn|error / report* etc.
13	 *   3. JUSTIFY IN WRITING carry a "// FAIL-OPEN: <reason>" comment inside or immediately above the catch
14	 *
15	 * A bare `catch (e) {}` or `catch {}` always fails.
16	 *
17	 * Engine: AST walk via acorn when it is installed (add acorn to devDependencies to get the precise walk);
18	 * otherwise a hardened regex + brace-matching fallback that skips string and comment contexts. Both engines
19	 * fail non-zero on the same core class, and the self-test proves whichever engine is active can see it.
20	 *
21	 * Modes:
22	 *   node tools/swallow-gate/check.js                  scan the repo source tree, exit 1 on any violation
23	 *   node tools/swallow-gate/check.js --json <path>    also write findings JSON for the sweep normaliser
24	 *   node tools/swallow-gate/check.js --calibrate      scan eval/calibration-known-bad/fixtures/ and REQUIRE
25	 *                                                     that seeded violations are found. Zero found = exit 1.
26	 */
27	const fs = require('fs');
28	const path = require('path');
29	
30	const { runGateCli, ROOT } = require('../lib/gate-cli');
31	
32	const SCAN_DIRS = ['catalogue', 'evidence', 'facts', 'applicability', 'breach', 'llm', 'payload', 'mint', 'render-proof', 'tools'];
33	
34	const RECORDER = /\b(?:_warn|warn|_record|record[A-Z_]\w*|addWarning|logWarning|manifest\.[A-Za-z_$]*(?:record|add|warn|note)\w*|logger?\.(?:warn|error)|console\.(?:warn|error)|log\.(?:warn|error)|report(?:Error|Failure|Warning)\w*|captureException)\s*\(/;
35	const JUSTIFY = /FAIL-OPEN:/;
36	
37	let acorn = null;
38	try { acorn = require('acorn'); }
39	catch (e) { acorn = null; /* FAIL-OPEN: acorn is an optional devDependency; the regex fallback below is the guaranteed engine and the self-test proves it works. */ }
40	// CI runs the self-test against BOTH engines: SWALLOW_GATE_ENGINE=regex forces the fallback even when acorn
41	// is installed, so the fallback can never rot unnoticed.
42	if (process.env.SWALLOW_GATE_ENGINE === 'regex') acorn = null;
43	
44	// ── fallback engine: comment/string-aware scan for catch blocks ─────────────────────────────────────────────
45	
46	// Walk the source character by character, tracking string/template/comment context, and return the index just
47	// past the matching close brace for the brace at `openIdx`.
48	function matchBrace(src, openIdx) {
49	  let depth = 0;
50	  let i = openIdx;
51	  while (i < src.length) {
52	    const c = src[i];
53	    const next = src[i + 1];
54	    if (c === '/' && next === '/') { const nl = src.indexOf('\n', i); i = nl === -1 ? src.length : nl + 1; continue; }
55	    if (c === '/' && next === '*') { const end = src.indexOf('*/', i + 2); i = end === -1 ? src.length : end + 2; continue; }
56	    if (c === '\'' || c === '"' || c === '`') {
57	      const q = c;
58	      i++;
59	      while (i < src.length && src[i] !== q) { if (src[i] === '\\') i++; i++; }
60	      i++;
61	      continue;
62	    }
63	    if (c === '{') depth++;
64	    if (c === '}') { depth--; if (depth === 0) return i + 1; }
65	    i++;
66	  }
67	  return src.length;
68	}
69	
70	// Find every catch clause with the fallback engine. Returns [{start, bodyStart, bodyEnd, line}].
71	function findCatchesRegex(src) {
72	  const out = [];
73	  const rx = /\bcatch\b\s*(\([^)]*\))?\s*\{/g;
74	  let m;
75	  while ((m = rx.exec(src)) !== null) {
76	    // Reject matches that sit inside a string or comment by rescanning context up to the match. Cheap and
77	    // exact enough: count unterminated context from the start of the line only, then a full scan when unsure.
78	    if (inStringOrComment(src, m.index)) continue;
79	    const openIdx = m.index + m[0].length - 1;
80	    const bodyEnd = matchBrace(src, openIdx);
81	    out.push({ start: m.index, bodyStart: openIdx + 1, bodyEnd: bodyEnd - 1, line: src.slice(0, m.index).split('\n').length });
82	  }
83	  return out;
84	}
85	
86	// True if position `idx` is inside a string, template or comment. Single forward scan.
87	function inStringOrComment(src, idx) {
88	  let i = 0;
89	  while (i < idx) {
90	    const c = src[i];
91	    const next = src[i + 1];
92	    if (c === '/' && next === '/') { const nl = src.indexOf('\n', i); if (nl === -1 || nl >= idx) return true; i = nl + 1; continue; }
93	    if (c === '/' && next === '*') { const end = src.indexOf('*/', i + 2); if (end === -1 || end + 2 > idx) return true; i = end + 2; continue; }
94	    if (c === '\'' || c === '"' || c === '`') {
95	      const q = c;
96	      i++;
97	      while (i < src.length && src[i] !== q) { if (src[i] === '\\') i++; i++; }
98	      if (i >= idx) return true;
99	      i++;
100	      continue;
101	    }
102	    i++;
103	  }
104	  return false;
105	}
106	
107	// ── acorn engine ────────────────────────────────────────────────────────────────────────────────────────────
108	
109	function findCatchesAcorn(src) {
110	  const ast = acorn.parse(src, { ecmaVersion: 'latest', allowHashBang: true, allowReturnOutsideFunction: true, allowAwaitOutsideFunction: true, locations: true });
111	  const out = [];
112	  (function walk(n) {
113	    if (!n || typeof n !== 'object') return;
114	    if (n.type === 'CatchClause') out.push({ start: n.start, bodyStart: n.body.start + 1, bodyEnd: n.body.end - 1, line: n.loc.start.line });
115	    for (const k of Object.keys(n)) {
116	      const v = n[k];
117	      if (Array.isArray(v)) v.forEach(walk);
118	      else if (v && typeof v.type === 'string') walk(v);
119	    }
120	  })(ast);
121	  return out;
122	}
123	
124	// ── shared judgement ────────────────────────────────────────────────────────────────────────────────────────
125	
126	function judgeCatch(src, c) {
127	  const body = src.slice(c.bodyStart, c.bodyEnd);
128	  // Justification may sit inside the body or on the two lines immediately above the catch.
129	  const before = src.slice(Math.max(0, src.lastIndexOf('\n', Math.max(0, src.lastIndexOf('\n', c.start - 1) - 1))), c.start);
130	  if (JUSTIFY.test(body) || JUSTIFY.test(before)) return null;
131	  if (/\bthrow\b/.test(body)) return null;
132	  if (RECORDER.test(body)) return null;
133	  const bare = body.replace(/\/\/[^\n]*|\/\*[\s\S]*?\*\//g, '').trim() === '';
134	  return {
135	    line: c.line,
136	    kind: bare ? 'bare-swallow' : 'silent-swallow',
137	    excerpt: ('catch ' + body.trim()).replace(/\s+/g, ' ').slice(0, 120),
138	  };
139	}
140	
141	function scanContent(src) {
142	  let catches;
143	  let engine;
144	  if (acorn) {
145	    try { catches = findCatchesAcorn(src); engine = 'acorn'; }
146	    catch (e) { throw new Error('acorn cannot parse this file: ' + e.message + ' (a parse failure is NOT zero catches)'); }
147	  } else {
148	    catches = findCatchesRegex(src);
149	    engine = 'regex-fallback';
150	  }
151	  const violations = [];
152	  for (const c of catches) {
153	    const v = judgeCatch(src, c);
154	    if (v) violations.push(v);
155	  }
156	  return { violations, catches: catches.length, engine };
157	}
158	
159	const { listJsFiles } = require('../lib/fswalk');
160	
161	function scanTree(dirs) {
162	  const violations = [];
163	  let scanned = 0;
164	  let catches = 0;
165	  for (const dir of dirs) {
166	    for (const abs of listJsFiles(path.join(ROOT, dir))) {
167	      scanned++;
168	      const rel = path.relative(ROOT, abs).replace(/\\/g, '/');
169	      const r = scanContent(fs.readFileSync(abs, 'utf8'));
170	      catches += r.catches;
171	      for (const v of r.violations) violations.push({ file: rel, ...v });
172	    }
173	  }
174	  return { violations, scanned, catches };
175	}
176	
177	// Self-test: prove the active engine can see the class this gate exists to catch.
178	function selfTest() {
179	  const cases = [
180	    { src: 'try { x(); } catch (e) {}', bad: 1 },                                                 // bare, bound
181	    { src: 'try { x(); } catch { }', bad: 1 },                                                    // bare, optional binding
182	    { src: 'try { x(); } catch (e) { count++; }', bad: 1 },                                       // silent: does something, records nothing
183	    { src: 'try { x(); } catch (e) { throw new Error("ctx: " + e.message); }', bad: 0 },          // rethrows
184	    { src: 'try { x(); } catch (e) { manifest.record("crawl", e); }', bad: 0 },                   // records
185	    { src: 'try { x(); } catch (e) { /* FAIL-OPEN: bonus signal only, madge is authoritative */ }', bad: 0 }, // justified
186	    { src: 'const s = "catch (e) {}";', bad: 0 },                                                 // catch inside a string is not a catch
187	  ];
188	  const results = cases.map((c) => {
189	    const got = scanContent(c.src).violations.length;
190	    return { want: c.bad, got, ok: got === c.bad, src: c.src };
191	  });
192	  const pass = results.every((r) => r.ok);
193	  return { pass, detail: results.filter((r) => !r.ok).map((r) => 'want ' + r.want + ' got ' + r.got + ' for: ' + r.src).join('; ') || 'all ' + cases.length + ' cases correct' };
194	}
195	
